export declare const code = "/* clip-path polygon() morphs smoothly IF vertex count matches */\n\n@keyframes morphPoly {\n  0% {\n    /* 10-point star \u2014 12 vertices */\n    clip-path: polygon(\n      50% 0%, 61% 35%, 98% 35%, 68% 57%,\n      79% 91%, 50% 70%, 21% 91%, 32% 57%,\n      2% 35%, 39% 35%, 50% 0%, 50% 0%\n    );\n  }\n  100% {\n    /* hexagon padded to 12 vertices */\n    clip-path: polygon(\n      50% 2%,  93% 26%, 93% 74%, 50% 98%,\n      7%  74%, 7%  26%, 50% 2%,  50% 2%,\n      50% 2%,  50% 2%,  50% 2%,  50% 2%\n    );\n  }\n}";
export default function I3PolygonMorph(): import("react/jsx-runtime").JSX.Element;
